#!/usr/bin/env node
/**
 * Design-tokens → CSS codegen.
 *
 * Single source of truth: `@chrono/design-tokens/v2` (TypeScript file
 * at packages/design-tokens/src/v2/colors.ts).
 *
 * Outputs (in-repo apps, ADR-0049):
 *   - apps/web/src/styles/globals.css        (@theme block)
 *   - apps/web/src/styles/themes.css         (data-theme overrides)
 *   - apps/desktop/src/index.css             (@theme block)
 *   - apps/companion-web/src/styles/tokens.css  (:root --c-* from shared companion theme; ADR-0046 D3)
 *
 * Each target file contains marker comments demarcating the
 * autogenerated region. Hand-written content above/below the markers
 * is preserved untouched.
 *
 * Marker format (literal, no whitespace variation):
 *   /* BEGIN AUTOGENERATED design-tokens — do not edit between markers *‌/
 *   ...content owned by this script...
 *   /* END AUTOGENERATED design-tokens *‌/
 *
 * Targets are in-repo apps/* and REQUIRED: a missing target CSS is an error
 * (not a skip), so GA always verifies the real app token CSS.
 *
 * Run:
 *   npm run codegen:design-tokens            # write
 *   npm run codegen:design-tokens -- --check # verify clean (CI)
 *
 * CI workflow: codegen → `git diff --exit-code` on the three output
 * files. Any diff = "someone forgot to run codegen after editing
 * tokens" — fix by running codegen locally and committing.
 */

import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const OS_ROOT = resolve(__dirname, '..');

/* web/desktop 已融合进本仓 apps/*（ADR-0049）；design-token CSS codegen 目标改为本地 apps/*，
 * 不再解析归档的 sibling 仓，缺目标即报错（不再 skip）——apps/* 现在是必校目标。 */
const WEB_ROOT = resolve(OS_ROOT, 'apps/web');
const DESKTOP_ROOT = resolve(OS_ROOT, 'apps/desktop');
const COMPANION_ROOT = resolve(OS_ROOT, 'apps/companion-web');

const BEGIN = '/* BEGIN AUTOGENERATED design-tokens — do not edit between markers */';
const END = '/* END AUTOGENERATED design-tokens */';

/* ── Load source tokens ─────────────────────────────────────────── */

const tokensModulePath = resolve(OS_ROOT, 'packages/design-tokens/dist/v2/colors.js');
const spacingModulePath = resolve(OS_ROOT, 'packages/design-tokens/dist/v2/spacing.js');
for (const p of [tokensModulePath, spacingModulePath]) {
  if (!existsSync(p)) {
    console.error(`✖ tokens source not built yet: ${p}`);
    console.error('  Run `npm run build` (or at least `tsc -b packages/design-tokens/tsconfig.json`) first.');
    process.exit(2);
  }
}
const { colorTokensLight, colorTokensDark, colorTokensHighContrast, colorTokensCompanion } =
  await import(tokensModulePath);
const { size: sizeTokens } = await import(spacingModulePath);

/* ── Helpers ─────────────────────────────────────────────────────── */

/** Convert a semantic tokens object into a flat `--color-…: value` map.
 *  Naming convention:
 *    surface.canvas       → --color-surface
 *    surface.elevated     → --color-surface-elevated
 *    text.primary         → --color-text-primary
 *    brand.primary        → --color-primary
 *    brand.primaryHover   → --color-primary-hover
 *    status.success       → --color-success
 *    chart[0]             → --color-chart-1
 *
 *  This map is chosen to match the *existing* CSS variable names in
 *  globals.css and themes.css so the codegen output drops in without
 *  touching any component. Renaming is a separate migration.
 */
function flattenColors(theme) {
  const out = {};
  /* surface */
  out['--color-surface'] = theme.surface.canvas;
  out['--color-surface-elevated'] = theme.surface.elevated;
  out['--color-surface-inverse'] = theme.surface.inverse;
  out['--color-overlay'] = theme.surface.overlay;
  /* text — every SemanticColors.text key must reach CSS so that
   * a token tweak (e.g. the text.tertiary WCAG bump) is observable
   * in the rendered DOM. Omitting any of these silently strands the
   * tweak inside the TS module. */
  out['--color-text-primary'] = theme.text.primary;
  out['--color-text-secondary'] = theme.text.secondary;
  out['--color-text-tertiary'] = theme.text.tertiary;
  out['--color-text-inverse'] = theme.text.inverse;
  out['--color-text-link'] = theme.text.link;
  /* border — `--color-border` keeps its short legacy name (= subtle);
   * the rest are emitted under their semantic names. */
  out['--color-border'] = theme.border.subtle;
  out['--color-border-default'] = theme.border.default;
  out['--color-border-strong'] = theme.border.strong;
  out['--color-border-focus'] = theme.border.focus;
  /* brand (mapped to current CSS variable names; primaryHover = "light"
   * is a legacy alias the components use to mean "hover/focus shade") */
  out['--color-primary'] = theme.brand.primary;
  out['--color-primary-light'] = theme.brand.primaryHover;
  out['--color-primary-active'] = theme.brand.primaryActive;
  out['--color-secondary'] = theme.brand.secondary;
  out['--color-secondary-light'] = theme.brand.secondaryHover;
  out['--color-accent'] = theme.brand.accent;
  out['--color-accent-light'] = theme.brand.accentHover;
  /* status */
  out['--color-success'] = theme.status.success;
  out['--color-warning'] = theme.status.warning;
  out['--color-error'] = theme.status.danger;
  out['--color-info'] = theme.status.info;
  out['--color-active'] = theme.status.active;
  out['--color-paused'] = theme.status.paused;
  out['--color-syncing'] = theme.status.syncing;
  out['--color-offline'] = theme.status.offline;
  out['--color-completed'] = theme.status.completed;
  /* chart */
  for (let i = 0; i < theme.chart.series.length; i += 1) {
    out[`--color-chart-${i + 1}`] = theme.chart.series[i];
  }
  out['--color-chart-grid'] = theme.chart.grid;
  out['--color-chart-positive'] = theme.chart.positive;
  out['--color-chart-negative'] = theme.chart.negative;
  /* neutral */
  out['--color-neutral-1'] = theme.neutral[1];
  out['--color-neutral-2'] = theme.neutral[2];
  out['--color-neutral-3'] = theme.neutral[3];
  return out;
}

/** Format a flat map as CSS declarations. Indentation is added by
 *  replaceMarkedRegion based on the BEGIN marker's column — we emit
 *  the declarations flush-left so the marker-aware indent insertion
 *  doesn't double up. */
function formatDeclarations(map) {
  return Object.entries(map)
    .map(([k, v]) => `${k}: ${v};`)
    .join('\n');
}

/** Replace the BEGIN/END region in a file, preserving indentation.
 *
 *  The BEGIN marker can be at any indent level (e.g. 2-space inside
 *  a `@theme { ... }` block). We capture the indent immediately
 *  preceding BEGIN and re-emit BEGIN + content + END with the same
 *  prefix on every line, so the marker block stays cosmetically
 *  consistent with its surrounding scope.
 *
 *  If the markers don't exist, return null so the caller can decide
 *  whether to bail or auto-insert (we bail — auto-inserting markers
 *  into an unfamiliar file would silently rewrite the structure). */
function replaceMarkedRegion(filePath, newRegion) {
  const original = readFileSync(filePath, 'utf8');
  const beginIdx = original.indexOf(BEGIN);
  const endIdx = original.indexOf(END);
  if (beginIdx === -1 || endIdx === -1) {
    return { ok: false, reason: 'missing markers' };
  }
  if (endIdx < beginIdx) {
    return { ok: false, reason: 'END marker before BEGIN' };
  }
  /* Determine the indent of the BEGIN marker by walking back to the
   * previous newline. We assume horizontal indent only (spaces or
   * tabs), which is true for CSS / TS / JS. */
  let lineStart = original.lastIndexOf('\n', beginIdx - 1) + 1;
  const indent = original.slice(lineStart, beginIdx);
  /* Strip the indent off every newRegion line that consists only of
   * whitespace + content (we'll re-add it). Don't touch blank lines. */
  const indentedRegion = newRegion
    .split('\n')
    .map(line => (line.length > 0 ? `${indent}${line}` : line))
    .join('\n');

  const before = original.slice(0, beginIdx);
  const after = original.slice(endIdx + END.length);
  const next = `${before}${BEGIN}\n${indentedRegion}\n${indent}${END}${after}`;
  return { ok: true, original, next };
}

/* ── Generators ─────────────────────────────────────────────────── */

/** Size / interactive-target tokens. Theme-independent so they ride
 *  along with the light theme @theme block in globals.css. Tailwind v4
 *  exposes `var(--size-*)` for sizing utilities via a custom config —
 *  the `--size-touch-target` variable is referenced via Tailwind's
 *  arbitrary-value syntax `min-h-[var(--size-touch-target)]`. */
function flattenSizes() {
  /* Two namespaces:
   *   --size-touch-target           — semantic alias, intended for
   *                                   `var(--size-touch-target)` in
   *                                   hand-written CSS or arbitrary-
   *                                   value Tailwind (`min-h-[var(...)]`).
   *   --min-height-touch            — Tailwind v4 maps the
   *                                   `--min-height-*` namespace into
   *                                   `min-h-touch` utility class,
   *                                   which is what components should
   *                                   prefer for terseness + intent.
   * Both resolve to the same physical value so renaming/migrating
   * downstream is mechanical. */
  return {
    '--size-touch-target': sizeTokens.touchTarget,
    '--size-touch-target-dense': sizeTokens.touchTargetDense,
    '--min-height-touch': sizeTokens.touchTarget,
    '--min-height-touch-dense': sizeTokens.touchTargetDense,
  };
}

function renderWebGlobalsTheme() {
  /* globals.css `@theme` block is Tailwind v4 source-of-truth for the
   * light theme. We emit only the @theme INNER (vars), letting the
   * surrounding `@theme { ... }` braces stay hand-written so future
   * non-color theme additions (fonts, shadows) don't fight the codegen. */
  const light = flattenColors(colorTokensLight);
  const sizes = flattenSizes();
  return [
    formatDeclarations(light),
    '',
    '/* Interactive target sizes (theme-independent). */',
    formatDeclarations(sizes),
  ].join('\n');
}

function renderWebThemesOverrides() {
  /* themes.css holds `[data-theme="dark"]` and `[data-theme="high-contrast"]`
   * + the `prefers-color-scheme: dark` fallback. Each selector's body
   * is indented one level relative to the selector; we emit declarations
   * flush-left within the block since the surrounding indent is the
   * marker's own column (typically 0 at the top of themes.css). */
  const dark = flattenColors(colorTokensDark);
  const hc = flattenColors(colorTokensHighContrast);

  const indentBlock = (text, prefix = '  ') =>
    text.split('\n').map(line => `${prefix}${line}`).join('\n');

  return [
    `:root[data-theme='dark'],`,
    `:root[data-theme='dark'] body {`,
    indentBlock(formatDeclarations(dark)),
    `}`,
    ``,
    `:root[data-theme='high-contrast'],`,
    `:root[data-theme='high-contrast'] body {`,
    indentBlock(formatDeclarations(hc)),
    `}`,
    ``,
    `/* OS-level dark preference, only when no explicit theme is set. */`,
    `@media (prefers-color-scheme: dark) {`,
    `  :root:not([data-theme]) {`,
    `    color-scheme: dark;`,
    indentBlock(formatDeclarations(dark), '    '),
    `  }`,
    `}`,
  ].join('\n');
}

function renderDesktopTheme() {
  /* Desktop currently uses `--color-chrono-*` prefix. Keep it (renaming
   * is a separate migration) but source the values from tokens. We emit
   * only the SAME six variables desktop currently uses; adding new ones
   * is a deliberate act. */
  const dark = flattenColors(colorTokensDark);
  /* Map web naming → desktop prefix. The set must cover every
   * `*-chrono-*` utility used in chrono-synth-desktop/src/**; missing
   * one means the utility falls back to undefined (renders nothing).
   *   --color-chrono-text-muted is an alias to text-tertiary kept for
   *   compatibility with existing `text-chrono-text-muted` call sites
   *   (4 page-level files). Either fold those to text-tertiary or keep
   *   the alias — alias chosen here to avoid a separate refactor PR. */
  const desktopVars = {
    '--color-chrono-primary': dark['--color-primary'],
    '--color-chrono-accent': dark['--color-accent'],
    '--color-chrono-surface': dark['--color-surface'],
    '--color-chrono-elevated': dark['--color-surface-elevated'],
    '--color-chrono-border': dark['--color-border'],
    '--color-chrono-text-primary': dark['--color-text-primary'],
    '--color-chrono-text-secondary': dark['--color-text-secondary'],
    '--color-chrono-text-tertiary': dark['--color-text-tertiary'],
    '--color-chrono-text-muted': dark['--color-text-tertiary'],
  };
  return formatDeclarations(desktopVars);
}

/** ChronoCompanion（C 端）token：把共享 `colorTokensCompanion` 映射回 companion-web
 *  既有的 `--c-*` 变量名。这样 companion 的 27 个手写组件 class（.card/.tabs/.chat…）
 *  **零改动**继续引用 `var(--c-*)`，但**取值来自共享 design-tokens 包**——单一事实源
 *  落地（ADR-0046 D3），同时不触碰任何组件（零视觉漂移）。
 *  companion 是单一暗色主题，输出一个 :root 块（无 data-theme 切换）。
 *  注意：companion styles.css 里非颜色 token（--c-space/radius/text/leading/gap）仍由
 *  styles.css 自己手写保留——P0 只统一**颜色**底座；间距/字号刻度的收编留待后续阶段。
 *  若 colorTokensCompanion 某字段缺失，此处解构会 fail-fast 抛错（非静默 undefined），codegen 即报错。 */
function renderCompanionTheme() {
  const c = colorTokensCompanion;
  const vars = {
    '--c-bg': c.surface.canvas,
    '--c-surface': c.surface.elevated,
    '--c-surface-2': c.neutral[2],
    '--c-text': c.text.primary,
    '--c-muted': c.text.secondary,
    '--c-brand': c.brand.primary,
    /* 加深品牌蓝：白字按钮背景，确保对比度 ≥4.5:1（WCAG AA）。 */
    '--c-brand-strong': c.brand.primaryActive,
    '--c-pos': c.status.success,
    '--c-neg': c.status.danger,
  };
  return formatDeclarations(vars);
}

/* Note: `formatDeclarations` returns flush-left text; the caller
 * (`replaceMarkedRegion`) prepends each line with the indent inferred
 * from the BEGIN marker's column, so the output sits cleanly inside
 * its surrounding scope. */

/* ── Target list ─────────────────────────────────────────────────── */

const TARGETS = [
  {
    repo: 'web',
    file: resolve(WEB_ROOT, 'src/styles/globals.css'),
    render: renderWebGlobalsTheme,
  },
  {
    repo: 'web',
    file: resolve(WEB_ROOT, 'src/styles/themes.css'),
    render: renderWebThemesOverrides,
  },
  {
    repo: 'desktop',
    file: resolve(DESKTOP_ROOT, 'src/index.css'),
    render: renderDesktopTheme,
  },
  {
    repo: 'companion-web',
    file: resolve(COMPANION_ROOT, 'src/styles/tokens.css'),
    render: renderCompanionTheme,
  },
];

/* ── Main ─────────────────────────────────────────────────────────── */

const args = process.argv.slice(2);
const checkOnly = args.includes('--check');

let totalChanged = 0;
let totalSkipped = 0;
let totalErrors = 0;

for (const target of TARGETS) {
  const rel = target.file.replace(OS_ROOT + '/', '');
  if (!existsSync(target.file)) {
    console.error(`✖ missing required target: ${rel}`);
    totalErrors += 1;
    continue;
  }

  const region = target.render();
  const result = replaceMarkedRegion(target.file, region);
  if (!result.ok) {
    console.error(`✖ ${rel}: ${result.reason}`);
    console.error(`  Add the markers manually around the region this script should own:`);
    console.error(`    ${BEGIN}`);
    console.error(`    /* codegen content goes here */`);
    console.error(`    ${END}`);
    totalErrors += 1;
    continue;
  }

  if (result.original === result.next) {
    console.log(`✓ unchanged: ${rel}`);
    continue;
  }

  if (checkOnly) {
    console.error(`✖ DRIFT: ${rel} (run \`npm run codegen:design-tokens\` and commit)`);
    totalErrors += 1;
    continue;
  }

  writeFileSync(target.file, result.next, 'utf8');
  console.log(`✓ wrote: ${rel}`);
  totalChanged += 1;
}

console.log('');
console.log(`changed=${totalChanged} skipped=${totalSkipped} errors=${totalErrors}`);

if (totalErrors > 0) process.exit(1);
process.exit(0);
